                        provider = SocialProvider.FACEBOOK,
                        id = result.accessToken.userId ?: "",
                        name = null,
                        email = null,
                        accessToken = token,
                        idToken = null,
                        photoUrl = null
                    )
                    pendingResult?.invoke(SocialAuthResult.Success(user))
                    pendingResult = null
                }

                override fun onCancel() {
                    pendingResult?.invoke(SocialAuthResult.Cancelled)
                    pendingResult = null
                }

                override fun onError(error: FacebookException) {
                    pendingResult?.invoke(SocialAuthResult.Error(error))
                    pendingResult = null
                }
            }
        )
    }

    override suspend fun signIn(activity: Activity): SocialAuthResult =
        suspendCancellableCoroutine { cont ->
            pendingResult = { result ->
                if (cont.isActive) cont.resume(result)
            }
            LoginManager.getInstance().logInWithReadPermissions(
                activity,
                listOf("public_profile", "email")
            )
        }

    override fun signOut(context: Context) {
        LoginManager.getInstance().logOut()
        AccessToken.setCurrentAccessToken(null)
    }
}

